#!/usr/bin/env bash
set -euo pipefail

OUTPUT="${1:?output path required}"
BASE_REF="${2:?base ref required}"
CURRENT_VERSION="${3:?current version required}"
LAST_TAG="${4:-none}"

mkdir -p "$(dirname "$OUTPUT")"

PROTO_DIFF=/tmp/proto-service.diff
SRC_DIFF=/tmp/src.diff
COMMITS=/tmp/commits.txt
BUF_OUT=/tmp/buf-breaking.txt
CONTEXT_DIR="$(dirname "$OUTPUT")"

git log "${BASE_REF}..HEAD" --oneline > "$COMMITS"
git diff "${BASE_REF}..HEAD" -- proto/service > "$PROTO_DIFF" || true
git diff "${BASE_REF}..HEAD" --stat -- src/ > /tmp/src-stat.txt || true
git diff "${BASE_REF}..HEAD" -- src/ > "$SRC_DIFF" || true

if [ -s "$SRC_DIFF" ]; then
  head -c 80000 "$SRC_DIFF" > /tmp/src-truncated.diff
else
  : > /tmp/src-truncated.diff
fi

if git diff --name-only "${BASE_REF}..HEAD" -- proto/service | grep -q .; then
  PROTO_CHANGED=true
else
  PROTO_CHANGED=false
fi

if [ -f proto/autogenerated/client.md ]; then
  git diff "${BASE_REF}..HEAD" -- proto/autogenerated/client.md > /tmp/client-doc.diff || true
else
  : > /tmp/client-doc.diff
fi

BUF_BREAKING=false
if [ "$LAST_TAG" != "none" ] && [ "$PROTO_CHANGED" = true ]; then
  if buf breaking proto --against ".git#ref=${LAST_TAG},subdir=proto" > "$BUF_OUT" 2>&1; then
    BUF_BREAKING=false
  else
    BUF_BREAKING=true
  fi
else
  echo "Skipped buf breaking (no prior tag or no proto changes)" > "$BUF_OUT"
fi

MIN_BUMP="patch"
if [ "$BUF_BREAKING" = true ]; then
  MIN_BUMP="major"
elif git diff --name-only "${BASE_REF}..HEAD" -- proto/service/methods.proto | grep -q .; then
  MIN_BUMP="minor"
fi

python3 - <<PY
import json
from pathlib import Path

context = {
    "current_version": "${CURRENT_VERSION}",
    "last_tag": "${LAST_TAG}",
    "base_ref": "${BASE_REF}",
    "buf_breaking": "${BUF_BREAKING}" == "true",
    "buf_output": Path("${BUF_OUT}").read_text(encoding="utf-8"),
    "proto_changed": "${PROTO_CHANGED}" == "true",
    "min_bump": "${MIN_BUMP}",
    "commits_path": "${COMMITS}",
    "proto_diff_path": "${PROTO_DIFF}",
    "src_diff_path": "/tmp/src-truncated.diff",
    "src_stat_path": "/tmp/src-stat.txt",
    "client_doc_diff_path": "/tmp/client-doc.diff",
}
Path("${OUTPUT}").write_text(json.dumps(context, indent=2) + "\n", encoding="utf-8")
PY

echo "Release context written to ${OUTPUT}"
echo "buf_breaking=${BUF_BREAKING} min_bump=${MIN_BUMP} proto_changed=${PROTO_CHANGED}"
